import {
  type Theme,
  type UserSession,
  updateUserSession,
} from "@/server/user-session";
import { useMutation } from "@tanstack/react-query";
import { getRouteApi, useRouter } from "@tanstack/react-router";

const rootRouteApi = getRouteApi("__root__");

export function useUserSession(): {
  session: UserSession;
  setSession: (update: Partial<UserSession>) => Promise<UserSession>;
  setTheme: (theme: Theme) => Promise<UserSession>;
  setSelectedTenantId: (id: number | null) => Promise<UserSession>;
  isPending: boolean;
} {
  const { userSession } = rootRouteApi.useLoaderData();
  const router = useRouter();

  const mutation = useMutation({
    mutationFn: (update: Partial<UserSession>) =>
      updateUserSession({ data: update }),
    onSuccess: () => router.invalidate(),
  });

  const setSession = (update: Partial<UserSession>) =>
    mutation.mutateAsync(update);

  return {
    session: userSession,
    setSession,
    setTheme: (theme: Theme) => setSession({ theme }),
    setSelectedTenantId: (id: number | null) =>
      setSession({ selectedTenantId: id }),
    isPending: mutation.isPending,
  };
}

