import type { Tenant } from "@/types/bootstrap";
import { beforeEach, describe, expect, it, vi } from "vitest";

type MockStore = { selectedTenantId: number | null; theme: "system" };

const store: MockStore = { selectedTenantId: null, theme: "system" };
const writeSpy = vi.fn<(update: Partial<MockStore>) => Promise<MockStore>>();

vi.mock("./user-session.server", () => ({
  readUserSession: vi.fn(async () => ({ ...store })),
  writeUserSession: (update: Partial<MockStore>) => writeSpy(update),
}));

const { resolveSelectedTenantId } = await import("./user-session");

function makeTenant(id: number, updated_at: string): Tenant {
  return {
    id,
    tenant_type: "org",
    name: `Tenant ${id}`,
    org_id: `org-${id}`,
    vendor_id: null,
    created_at: updated_at,
    updated_at,
  };
}

beforeEach(() => {
  store.selectedTenantId = null;
  store.theme = "system";
  writeSpy.mockReset();
  writeSpy.mockImplementation(async (update) => {
    Object.assign(store, update);
    return { ...store };
  });
});

describe("resolveSelectedTenantId", () => {
  it("returns null when there are no tenants", async () => {
    const result = await resolveSelectedTenantId([]);
    expect(result).toBeNull();
    expect(writeSpy).not.toHaveBeenCalled();
  });

  it("returns the stored id when it matches a tenant", async () => {
    store.selectedTenantId = 2;
    const tenants = [
      makeTenant(1, "2025-01-01T00:00:00Z"),
      makeTenant(2, "2025-02-01T00:00:00Z"),
    ];
    const result = await resolveSelectedTenantId(tenants);
    expect(result).toBe(2);
    expect(writeSpy).not.toHaveBeenCalled();
  });

  it("falls back to the most-recent tenant when stored id is invalid and persists it", async () => {
    store.selectedTenantId = 999;
    const tenants = [
      makeTenant(1, "2025-01-01T00:00:00Z"),
      makeTenant(2, "2025-03-01T00:00:00Z"),
      makeTenant(3, "2025-02-01T00:00:00Z"),
    ];
    const result = await resolveSelectedTenantId(tenants);
    expect(result).toBe(2);
    expect(writeSpy).toHaveBeenCalledWith({ selectedTenantId: 2 });
  });

  it("falls back to the most-recent tenant when no id is stored", async () => {
    const tenants = [
      makeTenant(10, "2025-01-01T00:00:00Z"),
      makeTenant(20, "2025-04-01T00:00:00Z"),
    ];
    const result = await resolveSelectedTenantId(tenants);
    expect(result).toBe(20);
    expect(writeSpy).toHaveBeenCalledWith({ selectedTenantId: 20 });
  });
});

